patch:
diff --git a/llvm/lib/IR/ConstantRange.cpp b/llvm/lib/IR/ConstantRange.cpp
index d81a292916fd..94c47493c633 100644
--- a/llvm/lib/IR/ConstantRange.cpp
+++ b/llvm/lib/IR/ConstantRange.cpp
@@ -1526,12 +1526,49 @@ ConstantRange ConstantRange::binaryAnd(const ConstantRange &Other) const {

   ConstantRange KnownBitsRange =
       fromKnownBits(toKnownBits() & Other.toKnownBits(), false);
-  ConstantRange UMinUMaxRange =
-      getNonEmpty(APInt::getZero(getBitWidth()),
-                  APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1);
+  
+  // Compute a better lower bound for the unsigned range.
+  APInt Lower = APInt::getZero(getBitWidth());
+  
+  // Check if we can compute a non-zero lower bound.
+  // If one operand guarantees bit k or higher is set (min >= 2^k), and the other
+  // operand has all bits k and above set to 1, then the result has bit k or higher set.
+  unsigned BitWidth = getBitWidth();
+  for (unsigned k = 0; k < BitWidth; ++k) {
+    APInt Threshold = APInt::getOneBitSet(BitWidth, k);
+    APInt MaskAboveK = APInt::getBitsSetFrom(BitWidth, k);
+    
+    // Check if this range guarantees bit k or higher is set.
+    APInt MinVal = getUnsignedMin();
+    bool ThisHasHighBit = MinVal.uge(Threshold);
+    
+    // Check if Other has all bits k and above set to 1.
+    KnownBits OtherKnown = Other.toKnownBits();
+    bool OtherHasAllHighBits = (OtherKnown.One & MaskAboveK) == MaskAboveK;
+    
+    if (ThisHasHighBit && OtherHasAllHighBits) {
+      Lower |= Threshold;
+      break;
+    }
+    
+    // Check the symmetric case.
+    APInt OtherMinVal = Other.getUnsignedMin();
+    bool OtherHasHighBit = OtherMinVal.uge(Threshold);
+    KnownBits ThisKnown = toKnownBits();
+    bool ThisHasAllHighBits = (ThisKnown.One & MaskAboveK) == MaskAboveK;
+    
+    if (OtherHasHighBit && ThisHasAllHighBits) {
+      Lower |= Threshold;
+      break;
+    }
+  }
+  
+  APInt Upper = APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1;
+  ConstantRange UMinUMaxRange = getNonEmpty(Lower, Upper);
   return KnownBitsRange.intersectWith(UMinUMaxRange);
 }

+
